import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        response.setContentType("text/html");
        response.setCharacterEncoding("UTF-8");

        // Output sanitized input
        response.getWriter().write("<h1>Welcome " + sanitizedInput + "</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
